PREFIX rdf:<http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?fasta
WHERE {
BIND (IRI(concat('http://purl.uniprot.org/annotation/',?featureId)) AS ?featureIRI)
{
?protein up:annotation ?featureIRI ;
         up:sequence/rdf:value ?sequence .
?featureIRI up:range ?range .
?range up:begin ?begin ;
       up:end   ?end .
BIND(substr(?sequence, ?begin, ?end-?begin+1) as ?seq) .
BIND(substr(str(?protein),33) as ?primAcc)
BIND(concat('>', ?primAcc, '#', ?featureId, '\\\\n', ?seq) AS ?fasta)
}
} LIMIT 10 OFFSET 0 VALUES (?featureId) {('PRO_0000024369')}

